// Mapează platforma sursă la marketplace-ul canonic și validează input-ul
const body = $input.first().json.body || {};
const sourcePlatform = (body.sourcePlatform || 'emag').toLowerCase();
const platformMap = {
  'emag': 'emag_ro',
  'trendyol': 'trendyol_ro',
  'temu': 'temu_ro'
};
const sourceMarketplace = platformMap[sourcePlatform] || (sourcePlatform + '_ro');
const sourceCategoryId = String(body.sourceCategoryId || '').trim();

if (!sourceCategoryId) {
  return [{ json: { _error: true, mappings: { trendyol: [], temu: [] } } }];
}

return [{ json: { sourceMarketplace, sourceCategoryId } }];

// Grupează rezultatele pe platformă target și marchează best per grup
const rows = $input.all().map(item => item.json);
const marketplaceToPlatform = {
  'trendyol_ro': 'trendyol',
  'temu_ro': 'temu'
};

const result = { trendyol: [], temu: [] };

for (const row of rows) {
  if (!row || !row.target_marketplace || !row.target_category_id) continue;
  const platform = marketplaceToPlatform[row.target_marketplace];
  if (!platform) continue;
  result[platform].push({
    categoryId: String(row.target_category_id),
    categoryName: row.target_category_name || ('Categorie ' + row.target_category_id),
    confidence: row.confidence || 'auto',
    usageCount: row.usage_count || 0,
    confirmedBy: row.confirmed_by || null,
    isBest: false
  });
}

// Primul item în fiecare grup e cel mai bun (deja sortat de SQL)
for (const platform of ['trendyol', 'temu']) {
  if (result[platform].length > 0) {
    result[platform][0].isBest = true;
  }
}

return [{ json: { mappings: result } }];
